/** Sorted list of pickable Lucide icon names (drives the admin picker search). */
export const NAV_ICON_NAMES: readonly string[] = Object.keys(NAV_ICON_COMPONENTS);

/** Resolve a Lucide name to a component, or null if not allowlisted. */
export function getLucideIcon(name: string | null | undefined): LucideIcon | null {
  if (!name) return null;
  return NAV_ICON_COMPONENTS[name] ?? null;
}
